// Извлекаем base64 из входящего запроса
// Сайт шлёт multipart/form-data с полями: photo (файл) и/или base64
const body = $input.first().json.body || {};
const binaryData = $input.first().binary || {};

let base64Image = '';
let mimeType = 'image/jpeg';

// Пробуем взять файл из binary
if (binaryData.photo && binaryData.photo.data) {
  base64Image = binaryData.photo.data;
  mimeType = binaryData.photo.mimeType || 'image/jpeg';
} else if (body.base64) {
  // Или берём base64 из поля
  base64Image = body.base64.replace(/^data:image\/[a-z]+;base64,/, '');
}

if (!base64Image) {
  throw new Error('Нет изображения в запросе');
}

return [{
  json: {
    base64: base64Image,
    mimeType: mimeType,
    source: body.source || 'website',
    timestamp: body.timestamp || new Date().toISOString()
  }
}];

// Парсим текстовый ответ llava-phi3
const raw = $input.first().json.response || '';
const cleaned = raw.replace(/```[a-z]*\n?/gi, '').replace(/```/g, '').trim();

const get = (label) => {
  const re = new RegExp('^' + label + '\\s*:\\s*([^\\n]+(?:\\n(?![A-ZА-ЯЁ][^\\n]*:\\s*).+)*)', 'mi');
  const m = cleaned.match(re);
  return m ? m[1].trim() : '';
};

const plantName = get('РАСТЕНИЕ') || 'Растение';
const problem = get('ПРОБЛЕМА') || 'Вероятная проблема не определена';
const categoryRaw = (get('КАТЕГОРИЯ') || 'unknown').toLowerCase();
const severityRaw = (get('СЕРЬЕЗНОСТЬ') || 'warn').toLowerCase();
const confidenceRaw = get('УВЕРЕННОСТЬ');
const diagnosis = get('ДИАГНОЗ') || cleaned || 'Не удалось извлечь описание из ответа модели.';
const recommendationsRaw = get('ЧТО ДЕЛАТЬ') || '';
const urgency = get('СРОЧНОСТЬ') || '';

const severity = severityRaw.includes('ok') || severityRaw.includes('здоров') ? 'ok'
  : severityRaw.includes('danger') || severityRaw.includes('critical') || severityRaw.includes('опас') ? 'danger'
  : 'warn';

const confidence = Math.max(0, Math.min(100, parseInt(confidenceRaw, 10) || (severity === 'ok' ? 84 : severity === 'danger' ? 76 : 58)));

const recommendations = recommendationsRaw
  ? recommendationsRaw.split(/\n+/).map(s => s.replace(/^[-*•\d.\s]+/, '').trim()).filter(Boolean).join('\n')
  : '1. Сделайте более чёткое фото\n2. Снимите лист с обеих сторон\n3. Добавьте фото всего растения';

const parsed = {
  plant_name: plantName,
  disease: problem,
  disease_category: categoryRaw,
  severity,
  confidence,
  diagnosis,
  recommendations,
  urgency,
  show_on_site: true
};

const prevData = $('Извлечь изображение').first().json;

return [{
  json: {
    ...parsed,
    source: prevData.source || 'website',
    timestamp: prevData.timestamp || new Date().toISOString(),
    raw_response: raw
  }
}];

// Формируем красивый ответ для сайта
const diagnosis = $('Парсить ответ Ollama').first().json;
const dbRow = $input.first().json;

const sevEmoji = { ok: '✅', warn: '⚠️', danger: '🚨' }[diagnosis.severity] || '⚠️';

return [{
  json: {
    id: dbRow.id || Date.now(),
    plant_name: diagnosis.plant_name,
    disease: diagnosis.disease,
    disease_category: diagnosis.disease_category,
    severity: diagnosis.severity,
    confidence: diagnosis.confidence,
    diagnosis: diagnosis.diagnosis,
    recommendations: diagnosis.recommendations,
    urgency: diagnosis.urgency,
    statusLabel: diagnosis.disease,
    status: diagnosis.severity,
    date: new Date().toLocaleString('ru-RU', { day:'2-digit', month:'2-digit', year:'numeric', hour:'2-digit', minute:'2-digit' }),
    icon: sevEmoji,
    show_on_site: diagnosis.show_on_site,
    _source: 'analysis-complete'
  }
}];
